UPDATE places SET overview = '골든듀는 정교한 장인정신과 세련된 디자인으로 사랑받는 대한민국 프리미엄 주얼리 브랜드입니다. 다이아몬드와 천연 보석을 활용한 컬렉션을 선보이며, 결혼과 기념일 등 특별한 순간을 위한 품격있는 주얼리를 제안합니다.' WHERE content_id = '4026648';
