UPDATE places SET overview = '노블워치는 전 세계의 고품격 타임피스를 엄선하여 소개하는 시계 전문 브랜드입니다. 명품 시계에 대한 깊은 조예와 신뢰할 수 있는 사후 관리 서비스를 통해 고객의 손목 위에 시간이 흘러도 변치 않는 품격을 선사합니다.' WHERE content_id = '4026656';
UPDATE places SET overview = '노블코코는 고귀하고 우아한 감성을 현대적인 여성복으로 풀어낸 브랜드입니다. 화사한 컬러 배색과 고급스러운 소재감을 통해 여성의 아름다움을 극대화해주며, 특별한 날은 물론 일상에서도 품격 있는 스타일링을 도와줍니다.' WHERE content_id = '4011579';
UPDATE places SET overview = '노스페이스는 기술력을 바탕으로 내구성 좋은 제품을 선보이는 글로벌 아웃도어 브랜드입니다. 뛰어난 성능을 갖춘 제품은 실생활에서 다양하게 활용됩니다. 특히 한국에서는 트렌디한 디자인으로 큰 인기를 얻고 있습니다.' WHERE content_id = '4011597';
UPDATE places SET overview = '노스페이스는 기술력을 바탕으로 내구성 좋은 제품을 선보이는 글로벌 아웃도어 브랜드입니다. 뛰어난 성능을 갖춘 제품은 실생활에서 다양하게 활용됩니다. 특히 한국에서는 트렌디한 디자인으로 큰 인기를 얻고 있습니다.' WHERE content_id = '2918331';
UPDATE places SET overview = '논픽션(NONFICTION)은 ''자신만의 본질''에 집중하는 시간을 제안하는 라이프스타일 뷰티 브랜드입니다. 매력적인 향기와 정제된 무드의 향수, 바디 케어 제품을 통해 일상의 소소한 순간에 맑은 영감과 힐링을 더해줍니다.' WHERE content_id = '4011553';
UPDATE places SET overview = '논현동 가구거리는 논현역 7호선과 학동역 사이에 가구 업체들이 밀집되어 있는 거리이다. 1970년부터 가구거리로 형성되었으며, 이때부터 가구거리라고 불렸다. 또한 강남구청에서 1996년 가구 문화 특화 거리로 지정하였다. 
논현동 가구거리를 방문하면 혼수용 가구, 공예 가구, 나전칠기, 부엌 가구, 사무용 가구, 인테리어, 수입 가구 등 가구의 모든 것을 한눈에 볼 수 있다. 고풍스러운 조명 등이 우리나라 가구의 1번지임을 돋보이게 하고 있다.' WHERE content_id = '132235';
UPDATE places SET overview = '논현문화마루도서관은 서울 강남구에 위치한 전국 최초의 예술 특화 도서관으로, 지역 주민들에게 책과 예술을 융합한 독창적 경험을 제공한다. 자연광이 가득한 현대적 건축과 아늑한 독서 공간, 어린이부터 성인까지 즐길 수 있는 다양한 프로그램을 자랑한다. 예술 관련 자료와 전시 공간이 특히 주목받고 있으며, 주민들이 문화와 창의성을 나눌 수 있는 커뮤니티 허브로 자리 잡고 있다.' WHERE content_id = '3432213';
UPDATE places SET overview = '서울시 강남구에 위치한 논현 손칼국수는 칼국수와 수제비에 고명으로 고기를 얹어주고 진한 육수가 일품인 식당이다. 멸치육수 베이스의 시원하고 구수한 국물과 쫄깃한 수제면이 특징이며 공깃밥과 면은 무한리필이 가능하다. 메뉴는 칼국수와 수제비, 칼+수제비가 있으며 여름철에는 콩국수도 맛볼 수 있다. 매장은 깔끔한 분위기로 편안한 식사 시간을 제공하며 언주역 근처에서 유명한 칼국수 맛집이다.' WHERE content_id = '2808941';
UPDATE places SET overview = '농민백암순대는 강남구 대치동에 위치한 순대 전문 식당으로 선릉역 1번 출구에서 도보로 6분 정도 거리에 있다. 대표 메뉴는 국밥과 토종 순대이며 직접 만든 순대와 함께 제공되는 고추, 양파, 부추 무침은 우리 농산물로만 사용한다고 한다. 그 국밥의 맛으로 이미 서울에서 3대 맛집으로 알려져 있으며 여러 매체에 소개되었다.' WHERE content_id = '2752169';
UPDATE places SET overview = '농협홍삼인삼은 우리 땅에서 정성껏 키운 인삼과 홍삼을 정직한 마음으로 담아낸 건강 전문 브랜드입니다. 농협의 엄격한 품질 관리를 거친 고품질의 홍삼 제품을 통해 현대인의 면역력 증진과 활력 회복을 돕습니다.' WHERE content_id = '4011563';
UPDATE places SET overview = '뉴발란스는 전 세계에서 사랑받는 글로벌 스포츠 브랜드입니다. 스타일리시한 디자인에 기능성까지 갖춘 운동화와 의류를 선보여 젊은 세대와 운동 마니아에게 꾸준한 인기를 얻고 있습니다.' WHERE content_id = '4011362';
UPDATE places SET overview = '뉴에라는 MLB 라이선스를 기반으로 한 글로벌 헤드웨어 브랜드입니다. 스트리트 패션 감성의 모자와 액세서리로 잘 알려져 있으며, 다양한 브랜드와의 콜라보레이션 제품도 인기가 높습니다.' WHERE content_id = '2915202';
UPDATE places SET overview = '뉴에라는 MLB 라이선스를 기반으로 한 글로벌 헤드웨어 브랜드입니다. 스트리트 패션 감성의 모자와 액세서리로 잘 알려져 있으며, 다양한 브랜드와의 콜라보레이션 제품도 인기가 높습니다.' WHERE content_id = '4011420';
UPDATE places SET overview = '뉴욕안경은 뉴욕의 세련된 감성과 전문적인 안 보건 서비스를 동시에 제공하는 아이웨어 전문 브랜드입니다. 최첨단 검안 시스템과 전 세계 하우스 브랜드 안경테 큐레이션을 통해 고객에게 가장 맑고 품격 있는 시야를 약속합니다.' WHERE content_id = '2910573';
UPDATE places SET overview = '느와르라르메스(Noir Larmes)는 ''검은 눈물''이라는 이름처럼 락 시크 무드와 다크한 감성을 담은 프리미엄 가죽 전문 브랜드입니다. 최상급 가죽 소재와 정교한 테일러링을 통해 강렬하고 지적인 남성미를 가장 우아하게 표현합니다.' WHERE content_id = '4026643';
UPDATE places SET overview = '늘복집은 지하철 3호선, 수인분당선 수서역 6번 출구 인근에 있다. 신선한 복을 활용한 다양한 요리를 선보이는 복요리 전문점이다. 다양한 코스 메뉴가 있으며, 복지리, 복튀김, 복사시미 등 단품 메뉴도 풍부하다. 특히 전복죽과 복죽은 크리미한 식감으로 고객들에게 사랑받고 있으며, 아늑한 분위기와 청결한 매장 관리가 만족도를 높여준다. 근처에 아래방죽마을공원, 윗방죽마을공원, 못골아래공원, 안개근린공원, 세곡공원이 있어 가벼운 산책이 가능하다.' WHERE content_id = '2870406';
UPDATE places SET overview = '구룡산 아래에 있는 능인선원은 부처님의 가르침인 지혜와 자비를 바탕으로 불자 양성과 포교 및 사회복지 증진을 위한 수행도량으로 설립되었다. 불교 포교와 공부하는 불자 양성으로 일관해 온 능인선원은 이제 대한민국 최고의 포교 사찰이 되었다. 능인(能仁)이란 능히 남을 교화하여 이롭게 하는 이라는 뜻을 지닌 석가모니 부처님의 다른 이름이다. 
능인선원에는 서울에서 유일하게 석가모니 부처님 본인의 진짜 진신사리가 봉안되어 있으며, 세계 최대 크기의 약사여래대불(질병쾌유부처님)이 있는 곳이다. 또한, 국내 최대 규모의 실내 법당을 보유하고 있다. 일반인을 대상으로 쉬운 불교강의를 하고 있다.' WHERE content_id = '1603149';
UPDATE places SET overview = '다니엘케이는 우아하고 클래식한 미학을 주얼리로 형상화하는 하이엔드 주얼리 브랜드입니다. 엄선된 다이아몬드와 유색 보석을 사용한 정교한 디자인을 통해 소중한 약속과 기념일을 가장 고귀한 빛으로 장식해드립니다.' WHERE content_id = '4026681';
UPDATE places SET overview = '다미(DAMI)는 정성이 가득 담긴 세련된 감각의 패션 및 주얼리 브랜드입니다. 고객의 아름다움을 정성스럽게 빚어낸다는 철학 아래 섬세한 디테일과 고급스러운 디자인의 아이템들을 선보여 특별한 매력을 완성해 드립니다.' WHERE content_id = '2904977';
