UPDATE places SET overview = '다미아니(Damiani)는 100년 전통을 지닌 이탈리아의 하이엔드 주얼리 브랜드로, 수작업 장인 정신의 정수를 보여줍니다. 독창적인 디자인과 최상급 보석의 화려한 광채를 통해 전 세계 셀러브리티와 왕실의 사랑을 받는 독보적인 가치를 전달합니다.' WHERE content_id = '4011497';
UPDATE places SET overview = '다비치안경은 세련된 디자인과 우수한 품질을 자랑하는 대한민국 안경 브랜드입니다. 트렌디하면서도 개성 넘치는 다양한 프레임을 합리적인 가격에 제공해, 외국인 관광객에게도 인기가 높습니다.' WHERE content_id = '2902972';
