UPDATE places SET overview = '디자인스킨은 모바일 기기를 나만의 개성으로 표현하는 국내 대표 프리미엄 모바일 액세서리 브랜드입니다. 세련된 가죽 케이스부터 트렌디한 디자인 상품까지, 소중한 스마트폰을 보호하는 동시에 스타일의 가치를 높여주는 제품을 제안합니다.' WHERE content_id = '4026724';
UPDATE places SET overview = '디젤(DIESEL)은 혁신적인 디자인과 반항적인 정신으로 무장한 글로벌 이탈리아 데님 및 라이프스타일 브랜드입니다. 파격적인 워싱 공법과 과감한 로고 플레이를 통해 전 세계 청춘들의 자유와 개성을 상징하는 아이콘으로 사랑받고 있습니다.' WHERE content_id = '4011504';
UPDATE places SET overview = '디젤(DIESEL)은 혁신적인 디자인과 반항적인 정신으로 무장한 글로벌 이탈리아 데님 및 라이프스타일 브랜드입니다. 파격적인 워싱 공법과 과감한 로고 플레이를 통해 전 세계 청춘들의 자유와 개성을 상징하는 아이콘으로 사랑받고 있습니다.' WHERE content_id = '4026740';
UPDATE places SET overview = '딘트(DINT)는 당당하고 화려한 여성의 당당한 아름다움을 완성해주는 고감도 여성복 브랜드입니다. 독보적인 디자인과 과감한 실루엣의 의류를 통해 자신만의 뚜렷한 아우라를 표현하고자 하는 여성들의 지지를 받고 있습니다.' WHERE content_id = '4011463';
UPDATE places SET overview = '한우 다이닝 뜨락은 1998년 청담동의 작은 주택에서 시작한 이래 지금껏 최상급 한우의 정수를 선보이며 미식가들과 손님들에게 꾸준한 사랑과 신뢰를 받아 ‘2024년 서울 미식 100선’에 선정된 바가 있는 곳이다. 2024년 1월 새롭게 오픈한 신관과 11월 리뉴얼된 본관은 세련된 인테리어와 한층 업그레이드된 시설로 더욱 편안하고 품격 있는 다이닝 경험을 제공한다.
뜨락의 대표메뉴인 안심을 즐길 수 있는 정식 A, 최상 등급의 등심을 즐길 수 있는 정식 B, 뜨락의 시그니처인 안심과 안창살을 모두 즐길 수 있는 정식 C 등 다양한 메뉴가 준비되어 있다.' WHERE content_id = '2845699';
UPDATE places SET overview = '라디오아이즈는 음악적 감성과 개성 있는 디자인이 결합된 국내 대표 하우스 브랜드 안경입니다. 기존의 틀을 깨는 독창적인 프레임과 다채로운 컬러를 통해 안경을 하나의 패션 아이콘으로 즐기는 고객들에게 영감을 선사합니다.' WHERE content_id = '2904968';
UPDATE places SET overview = '라미(LAMY)는 독일의 정교한 공학 기술과 미니멀한 디자인이 결합된 글로벌 필기구 브랜드입니다. ''형태는 기능을 따른다''는 철학 아래 탄생한 만년필과 볼펜을 통해 일상적인 기록의 순간을 예술적인 경험으로 바꿔줍니다.' WHERE content_id = '4011611';
UPDATE places SET overview = '라온안경원은 ''즐거운''이라는 뜻의 순우리말 이름처럼 고객에게 즐겁고 밝은 시야를 선물합니다. 최첨단 검안 시스템과 감각적인 디자인의 안경테 큐레이션을 통해 고객의 눈 건강과 스타일을 동시에 만족시켜드립니다.' WHERE content_id = '4026682';
UPDATE places SET overview = '라운지엘(LOUNGE L)은 여유로운 휴식과 세련된 패션이 조화된 라이프스타일 큐레이션 브랜드입니다. 편안하면서도 스타일리시한 의류와 잡화를 통해 매일매일이 호텔 라운지에서 쉬는 듯한 특별한 기분을 선사합니다.' WHERE content_id = '4026686';
UPDATE places SET overview = '라움(RAUM)은 LG패션에서 운영하는 품격 있는 라이프스타일 편집 브랜드입니다. 전 세계의 수준 높은 패션과 홈 데코 아이템들을 감각적인 안목으로 큐레이션하여 고객의 일상 공간에 예술적인 영감과 여유를 더해줍니다.' WHERE content_id = '4026698';
UPDATE places SET overview = '라움아트센터는 사회적 교류의 장소라는 의미의 소셜 베뉴(Social Venue)의 가치를 실현하고자 하는 복합문화공간이며, 품격 높은 공연과 아카데미 그리고 연회와 웨딩을 주로 하고 있다. 전체적인 디자인은 스코틀랜드의 스키보 캐슬(Skibo Castle)을 모티브로 건축된 고성을 연상시키며 하우스, 가든, 스몰, 채플의 다양한 분위기를 조성할 수 있다. 지하 1층부터 4층까지로 이루어진 라움아트센터는 파티와 콘서트 그리고 웨딩을 위한 넓고 럭셔리한 분위기의 홀을 구비하고 있다.  마제스틱 볼룸, 갤러리 홀, 챔버홀, 가든 네 개의 홀로, 이 공간에서 페스티벌, 테마 콘서트, 클래식  연주회, 파티, 아카데미, 세미나, 초청행사 등 다양한 행사를 개최한다.' WHERE content_id = '3074841';
UPDATE places SET overview = '라이카(Leica)는 100년이 넘는 역사와 정밀 광학 기술의 정수를 담은 전설적인 독일의 카메라 브랜드입니다. 빨간 점 로고로 상징되는 독보적인 미학과 뛰어난 묘사력을 통해 사진작가들의 영감을 현실로 구현하는 최고의 도구를 제공합니다.' WHERE content_id = '4011414';
UPDATE places SET overview = '라이카(Leica)는 100년이 넘는 역사와 정밀 광학 기술의 정수를 담은 전설적인 독일의 카메라 브랜드입니다. 빨간 점 로고로 상징되는 독보적인 미학과 뛰어난 묘사력을 통해 사진작가들의 영감을 현실로 구현하는 최고의 도구를 제공합니다.' WHERE content_id = '2925732';
UPDATE places SET overview = '라이프워크는 강렬한 캐릭터 ''라독'' 로고로 유명한 유니크 스트릿 캐주얼 브랜드입니다. 스포티한 감성에 힙한 스트릿 무드를 더한 디자인의 의류를 통해 자신만의 개성을 당당하게 표현하는 젊은 세대의 지지를 받습니다.' WHERE content_id = '4011668';
UPDATE places SET overview = '라인프렌즈(LINE FRIENDS)는 브라운, 코니 등 전 세계적으로 사랑받는 캐릭터를 기반으로 한 글로벌 크리에이티브 스토어입니다. 위트 넘치는 캐릭터 굿즈와 다채로운 라이프스타일 상품을 통해 일상에 즐거운 활력과 미소를 전합니다.' WHERE content_id = '4026629';
UPDATE places SET overview = '라코스테는 프랑스의 우아함과 스포티한 감성이 결합된 프리미엄 패션 브랜드입니다. 상징적인 피케 셔츠를 비롯해 고급스러운 소재와 정제된 실루엣의 제품들을 선보이며 전 세계적으로 시대를 초월한 사랑을 받고 있습니다.' WHERE content_id = '2912526';
UPDATE places SET overview = '락피쉬웨더웨어는 영국의 클래식한 웨더웨어 감성을 현대적인 라이프스타일로 제안하는 브랜드입니다. 아이코닉한 레인 부츠부터 세련된 플랫슈즈까지, 날씨에 구애받지 않고 즐길 수 있는 기능성과 패션성을 동시에 갖춘 아이템을 선보입니다.' WHERE content_id = '4011422';
UPDATE places SET overview = '랑방컬렉션은 프랑스 랑방 하우스의 우아한 오리지널리티를 현대적인 감각으로 재해석한 브랜드입니다. 고급스러운 소재와 화려한 드레이핑 기술을 통해 여성의 곡선미를 아름답게 살려주는 컬렉션을 선보입니다.' WHERE content_id = '2918404';
UPDATE places SET overview = '랑에운트죄네(A. Lange & Söhne)는 독일 정밀 기계 공학의 정점에 서 있는 하이엔드 워치 메이킹 브랜드입니다. 타협하지 않는 품질과 정교한 기계적 메커니즘, 독일 특유의 절제된 디자인을 통해 시계 예술의 최고 가치를 전달합니다.' WHERE content_id = '4011537';
UPDATE places SET overview = '래코드(RE;CODE)는 대한민국을 대표하는 업사이클링 기반의 컨템포러리 패션 브랜드입니다. 버려지는 의류와 재고 소재를 새로운 예술적 가치로 재탄생시키며, 지속 가능한 패션의 철학과 독창적인 디자인을 동시에 선도합니다.' WHERE content_id = '4026668';
UPDATE places SET overview = '러쉬는 신선한 천연 성분과 핸드메이드 방식을 고집하는 영국의 프레쉬 코스메틱 브랜드입니다. 강렬한 향기와 다채로운 컬러의 입욕제, 비누 등을 선보이며 환경 보호와 동물 복지를 실천하는 윤리적인 브랜드로 유명합니다.' WHERE content_id = '2915158';
UPDATE places SET overview = '러쉬스파는 영국의 프레쉬 코스메틱 러쉬의 철학을 오감으로 경험할 수 있는 힐링 공간입니다. 독창적인 음악과 테라피스트의 섬세한 터치를 결합한 프로그램을 통해 몸과 마음의 긴장을 풀어주고 진정한 휴식을 선사합니다.' WHERE content_id = '4011571';
UPDATE places SET overview = '러퓸(LUVFUME)은 사랑스러운 향기로 공간과 기억을 채워주는 감성 프래그런스 브랜드입니다. 일상의 소소한 순간에 따뜻한 위안을 주는 핸드크림, 향수 등 다양한 라인업을 통해 감각적인 휴식과 힐링을 선사합니다.' WHERE content_id = '4011669';
UPDATE places SET overview = '럭키슈에뜨는 유니크하고 위트 있는 디자인으로 사랑받는 영 캐릭터 캐주얼 브랜드입니다. 시그니처인 올빼미 캐릭터와 과감한 컬러 매치를 통해 자신만의 개성을 당당하게 표현하는 여성들을 위한 스타일을 제안합니다.' WHERE content_id = '2924678';
UPDATE places SET overview = '레드마블하우스는 서울지하철 2호선 역삼역 1번 출구 구역삼세무서 사거리 부근에 있다. 매장이 있는 상가건물에 자체 주차장이 있어 방문 시 자동차로 이용하기 편리하다. 이곳은 국내 대표기업 밀집 지역인 역삼동에 비즈니스 자리를 위한 전문 한우식당이다. 매장 내부는 넓은 홀에 인원별 다양한 테이블 구성과 개별 룸까지 있어 단체 행사나 가족 모임에도 적당하다. 대표 메뉴는 레드 마블 코냑 눈꽃등심, 레드 마블 눈꽃등심, 레드 마블 생/양념갈비, 레드 마블 명품 살치살이 있다. 이외 메뉴로 한우 로스편채, 레드 마블 한우 샤부샤부, 한우갈비탕이 인기가 많다. 주변에 서울선릉과정릉(세계문화유산), 잠실종합운동장, 잠원한강공원, 코엑스 등이 있어 연계 관광을 할 수 있다.' WHERE content_id = '2870000';
UPDATE places SET overview = '레몬버베나는 상큼하고 싱그러운 향기를 담아낸 라이프스타일 프래그런스 브랜드입니다. 자연에서 온 기분 좋은 향을 담은 디퓨저와 스킨케어 제품을 통해 지친 현대인의 심신에 맑은 휴식과 활력을 불어넣어줍니다.' WHERE content_id = '4026665';
UPDATE places SET overview = '레스쁘아는 수인·분당선 압구정로데오역 4번 출구 도산대로 청담동 거리에 있다. 주차는 매장이 있는 건물에 할 수 있고 발렛파킹 서비스를 이용할 수 있다. 프랑스 파리를 옮겨 놓은 듯한 인테리어와 테라스가 인상적이다. 2008년부터 꾸준히 클래식한 프랑스 지역 음식들을 현지 모습 그대로 소개하고 있다. 대표 메뉴는 오리콩피와 양파 수프다. 그 외 런치코스, 하우스 스페셜이 있다. 식당 인근에 청담동 명품 거리, 압구정로데오거리, 압구정 카페거리가 있어 연계 관광을 할 수 있다.' WHERE content_id = '2869691';
UPDATE places SET overview = '레스포색(LeSportsac)은 가벼운 나일론 소재와 다채로운 프린트로 유명한 미국의 글로벌 가방 브랜드입니다. 실용적인 수납 공간과 패셔너블한 디자인을 조화시켜 일상의 외출부터 여행까지 전 세계인들의 가벼운 발걸음을 함께합니다.' WHERE content_id = '4026666';
UPDATE places SET overview = '레아트성형외과의원은 얼굴과 체형의 조화를 예술적(Art)인 감각으로 빚어내는 성형 전문 의료기관입니다. 풍부한 수술 경험과 첨단 장비를 바탕으로 환자가 꿈꾸던 변화를 자연스럽고 안전하게 실현하여 최상의 만족을 드립니다.' WHERE content_id = '2910004';
UPDATE places SET overview = '레오나드는 화려한 플라워 프린트와 정교한 수작업 날염 기술로 유명한 프랑스 럭셔리 브랜드입니다. ''입는 보석''이라 불릴 만큼 아름다운 색채의 실크 의류를 통해 독보적인 우아함과 기품을 표현합니다.' WHERE content_id = '2918173';
UPDATE places SET overview = '레페토(repetto)는 프랑스 발레 의상에서 영감을 받은 세계적인 럭셔리 슈즈 브랜드입니다. ''스티치 앤 리턴'' 공법으로 제작된 유연하고 편안한 플랫슈즈를 통해 우아하고 자유로운 발걸음의 정수를 선사합니다.' WHERE content_id = '4011488';
UPDATE places SET overview = '렉스관광호텔은 정갈한 서비스와 합리적인 가격, 절제된 디자인과 효율적인 공간 배치로, 집에 머무는 듯한 아늑한 휴식을 제공한다. 여행자의 라이프스타일을 반영한 다양한 객실 구조와 고객을 먼저 생각하는 이곳은 디럭스 더블룸, 디럭스 트윈룸, 패밀리 트윈룸의 3가지 타입의 객실로 구성되어 있다. 각 룸은 비즈니스 출장, 파티, 그리고 연인들이 다용도로 이용하기 편안한 객실로 편안한 침대와 넓고 편리한 테이블이 구비되어 있다.' WHERE content_id = '3080539';
UPDATE places SET overview = '렌즈미는 국내 최대 규모의 디자인 렌즈 라인업을 보유한 컬러렌즈 전문 브랜드입니다. 최신 트렌드를 반영한 다채로운 그래픽 렌즈와 편안한 소재의 제품을 통해 고객들의 눈빛 스타일링을 완성해 줍니다.' WHERE content_id = '4026619';
UPDATE places SET overview = '로데오안경원은 ''안경 맞춤 전문가''들이 정밀한 검안과 피팅을 통해 세상에 단 하나뿐인 편안함을 제공하는 안경원입니다. 고객의 얼굴형과 도수에 최적화된 안경을 제안하여 최상의 시력 보정 경험을 선사합니다.' WHERE content_id = '4026675';
UPDATE places SET overview = '로로피아나는 이탈리아 최고의 캐시미어와 울 소재를 자랑하는 세계 최상급 럭셔리 브랜드입니다. ''소리 없는 럭셔리''의 대명사로서 타협하지 않는 품질과 우아한 실루엣을 통해 시대를 초월한 기품을 선사합니다.' WHERE content_id = '4026710';
UPDATE places SET overview = '로맨시크(ROMANCHIC)는 로맨틱한 소녀의 감성과 시크한 여성미가 공존하는 디자이너 브랜드입니다. 섬세한 자수와 레이스 디테일, 구조적인 실루엣을 통해 입는 사람을 드라마틱한 주인공으로 만들어주는 특별한 컬렉션을 선보입니다.' WHERE content_id = '4026725';
UPDATE places SET overview = '로얄 라운지 다이닝은 미쉐린 2스타&그린 스타 La Peca 출신의 김경훈 셰프의 모던 이탈리안 다이닝 레스토랑이다. 세련된 인테리어와 우아한 분위기 속에서  계절별 신선한 식재료를 활용한 정통 프렌치 요리를 선보인다. 전문 소믈리에가 추천하는 와인과의 페어링을 통해 미각의 조화를 이끌어낸다. 특별한 날을 더욱 특별하게 만들어주는 프라이빗한 다이닝룸도 마련되어 있어 소중한 사람과의 소중한 시간을 더욱 빛나게 한다. 로얄 라운지 다이닝 레스토랑은 품격 있는 식사를 원하는 이들에게 최적의 선택이다.' WHERE content_id = '2846959';
UPDATE places SET overview = '로에베(LOEWE)는 스페인의 오랜 가죽 공예 전통을 현대적인 예술 감각으로 승화시킨 하이엔드 럭셔리 하우스입니다. 혁신적인 실루엣의 가방과 위트 넘치는 의류 컬렉션을 통해 전 세계 패션계에 신선한 영감과 품격 있는 미학을 선사합니다.' WHERE content_id = '2918575';
UPDATE places SET overview = '로에베(LOEWE)는 스페인의 오랜 가죽 공예 전통을 현대적인 예술 감각으로 승화시킨 하이엔드 럭셔리 하우스입니다. 혁신적인 실루엣의 가방과 위트 넘치는 의류 컬렉션을 통해 전 세계 패션계에 신선한 영감과 품격 있는 미학을 선사합니다.' WHERE content_id = '4011496';
UPDATE places SET overview = '로우클래식(LOW CLASSIC)은 서울의 모던하고 시크한 감성을 대표하는 디자이너 여성복 브랜드입니다. 클래식한 미학을 기반으로 위트 있는 디테일을 가미한 미니멀한 의류를 통해 전 세계적인 팬덤을 보유하고 있습니다.' WHERE content_id = '2923509';
UPDATE places SET overview = '로이드는 합리적인 가격으로 고급스러운 감성을 즐길 수 있는 기프트 주얼리 브랜드입니다. 클래식한 시계부터 트렌디한 액세서리까지 폭넓은 라인업을 통해 특별한 순간을 더욱 빛나게 만드는 선물을 제안합니다.' WHERE content_id = '4011361';
UPDATE places SET overview = '로이성형외과의원은 정통 성형의 기본을 지키면서도 최신 뷰티 트렌드를 반영하여 조화로운 아름다움을 추구하는 의료기관입니다. 환자와의 충분한 소통을 통해 개성을 살린 세련된 디자인을 제안하며 안전한 수술을 약속합니다.' WHERE content_id = '3307161';
UPDATE places SET overview = '로저비비에는 상징적인 사각 버클 장식으로 전 세계 여성들의 마음을 사로잡은 프랑스의 럭셔리 슈즈 및 액세서리 브랜드입니다. 예술 작품과 같은 정교한 디자인과 화려한 소재를 통해 시대를 초월한 우아함의 정수를 보여줍니다.' WHERE content_id = '2925647';
UPDATE places SET overview = '로저비비에는 상징적인 사각 버클 장식으로 전 세계 여성들의 마음을 사로잡은 프랑스의 럭셔리 슈즈 및 액세서리 브랜드입니다. 예술 작품과 같은 정교한 디자인과 화려한 소재를 통해 시대를 초월한 우아함의 정수를 보여줍니다.' WHERE content_id = '4026752';
UPDATE places SET overview = '로저비비에는 상징적인 사각 버클 장식으로 전 세계 여성들의 마음을 사로잡은 프랑스의 럭셔리 슈즈 및 액세서리 브랜드입니다. 예술 작품과 같은 정교한 디자인과 화려한 소재를 통해 시대를 초월한 우아함의 정수를 보여줍니다.' WHERE content_id = '2925805';
UPDATE places SET overview = '록시땅(L''OCCITANE)은 프랑스 프로방스의 풍요로운 대자연과 전통 보존 방식을 담은 자연주의 뷰티 브랜드입니다. 시어 버터 등 엄선된 천연 원료를 활용한 스킨케어와 바디 케어 제품을 통해 고객의 몸과 마음에 편안한 휴식과 진정한 아름다움을 선사합니다.' WHERE content_id = '2924608';
UPDATE places SET overview = '롤렉스(ROLEX)는 정확성, 내구성, 신뢰성을 바탕으로 전 세계 시계 제조 업계의 정점으로 꼽히는 스위스 명품 워치 브랜드입니다. ''서브마리너'', ''데이트저스트'' 등 시대를 초월하는 아이코닉한 타임피스로 최고의 가치를 전달합니다.' WHERE content_id = '2927748';
UPDATE places SET overview = '롤렉스(ROLEX)는 정확성, 내구성, 신뢰성을 바탕으로 전 세계 시계 제조 업계의 정점으로 꼽히는 스위스 명품 워치 브랜드입니다. ''서브마리너'', ''데이트저스트'' 등 시대를 초월하는 아이코닉한 타임피스로 최고의 가치를 전달합니다.' WHERE content_id = '2905645';
UPDATE places SET overview = '롯데백화점은 글로벌 명품부터 K-패션, 뷰티, 식음료까지 다양한 브랜드를 한곳에서 만나볼 수 있는 프리미엄 쇼핑센터입니다. 쾌적한 공간과 수준 높은 서비스로 외국인 관광객에게도 인기가 높습니다.' WHERE content_id = '2908572';
UPDATE places SET overview = '롯데하이마트는 대한민국의 가전제품 전문 유통 브랜드로, 생활가전부터 스마트기기까지 다양한 전자제품을 한곳에서 만나볼 수 있습니다. 전국 300여 개 매장과 온라인 쇼핑몰에서 합리적인 가격과 전문 상담 서비스를 제공합니다.' WHERE content_id = '2910800';
UPDATE places SET overview = '롯데호텔 L7 강남은 서울 강남의 중심에 위치한 비즈니스호텔로, 서울 MICE 중심지인 코엑스와 인접해 국내외 방문객들에게 편리한 접근성을 제공한다. 레스토랑&바 ‘플로팅’에서는 특급 요리사들이 제철 식재료로 선보이는 건강한 식사와 스낵을 즐길 수 있다. 투숙객을 위한 풋스파가 마련된 야외 테라스와 테크노짐의 최신 운동기구를 갖춘 피트니스센터, 지하주차장, 회의장 등 다양한 편의시설을 보유하고 있다. L7 강남은 롯데호텔의 라이프스타일 브랜드로서 트렌디한 디자인과 편안한 베딩 시스템을 통해 도심 속 여유를 제공한다. 객실비용은 합리적으로 유지하면서도 서비스 품질을 높여 고객 만족도를 극대화하고 있다.' WHERE content_id = '2548198';
UPDATE places SET overview = '루비떡볶이는 압구정로데오역 근처에 위치한 분식 전문점이다. 수요미식회 등 다양한 프로그램에서 소개가 될 정도로 인기 있는 떡볶이 맛집이다. 대표메뉴인 새우깡떡볶이는 튀긴 작은 새우를 떡볶이 위에 토핑으로 올라가는데 바삭한 새우깡과 쫄깃한 떡, 매콤한 소스의 조합이 아주 잘 어울린다. 색다른 맛의 떡볶이를 찾는다면 강력 추천한다.' WHERE content_id = '2731162';
UPDATE places SET overview = '루비약국은 보석 루비처럼 투명하고 정직한 약료 서비스를 통해 고객의 건강을 밝혀드립니다. 친절한 복약 지도와 체계적인 처방 조제 시스템을 갖추어 지역 주민들이 믿고 찾을 수 있는 건강한 쉼터가 되겠습니다.' WHERE content_id = '4011379';
UPDATE places SET overview = '중국어로 ‘모든 일이 뜻대로 되다’라는 뜻을 가진 루위는 프리미엄 중식 레스토랑으로, 다양한 TV 프로그램에 소개된 맛집이다. 인근 압구정과 가로수길 일대 맛집으로도 유명한 곳이다. 
다양한 룸을 보유하고 있어 강남에서 상견례, 소규모 돌잔치, 부모님 생신잔치, 송년회 같은 단체모임 등 각종 모임 장소로 주목받고 있으며, 재방문하는 단골 고객층이 매우 두터운 곳이다. 
루위의 대표메뉴는 겉은 바삭바삭하면서도 속은 촉촉한 북경오리이다. 육즙이 풍부하게 나오면서 씹는 식감이 독특한 보양식이다. 북경오리는 하루 전 예약 주문이 필수이다. 이외에도 중식 소안심 스테이크, 불도장, 황비홍 라즈윙, 조연중새우 등이 있다.' WHERE content_id = '2602869';
UPDATE places SET overview = '루이까스텔은 위트 있는 로고와 다채로운 컬러 배색이 돋보이는 프리미엄 골프웨어 브랜드입니다. 뛰어난 신축성과 기능성 소재를 사용하여 필드에서의 활동성을 극대화하며 스타일리시한 골프 룩을 완성해 줍니다.' WHERE content_id = '4011457';
UPDATE places SET overview = '루이비통(Louis Vuitton)은 여행의 예술을 근간으로 하는 전 세계 럭셔리 산업의 선구자이자 글로벌 하이엔드 하우스입니다. 상징적인 모노그램 패턴과 혁신적인 디자인을 통해 패션, 잡화, 액세서리 전반에서 독보적인 가치와 장인 정신을 전합니다.' WHERE content_id = '2905894';
UPDATE places SET overview = '루이비통(Louis Vuitton)은 여행의 예술을 근간으로 하는 전 세계 럭셔리 산업의 선구자이자 글로벌 하이엔드 하우스입니다. 상징적인 모노그램 패턴과 혁신적인 디자인을 통해 패션, 잡화, 액세서리 전반에서 독보적인 가치와 장인 정신을 전합니다.' WHERE content_id = '2916471';
UPDATE places SET overview = '루이비통여성은 프랑스 하이엔드 하우스 루이비통의 예술적인 감성과 장인 정신이 집약된 여성 전용 라인입니다. 상징적인 핸드백부터 우아한 레디 투 웨어까지, 전 세계 여성들에게 독보적인 럭셔리 라이프스타일의 정수를 선사합니다.' WHERE content_id = '2911177';
UPDATE places SET overview = '루첸리는 빛의 영롱함과 다이아몬드의 영원한 가치를 담아낸 프리미엄 예물 및 주얼리 브랜드입니다. 숙련된 장인의 정교한 세공을 통해 인생의 가장 빛나는 순간을 약속하는 고품격 주얼리 컬렉션을 선보입니다.' WHERE content_id = '2910204';
UPDATE places SET overview = '룩옵티컬은 ''안경은 얼굴이다''라는 철학 아래 누구나 쉽고 즐겁게 안경을 쇼핑할 수 있는 안경 전문 브랜드입니다. 수천 가지의 트렌디한 안경테를 직접 써보고 비교하며 자신에게 가장 잘 어울리는 스타일을 찾을 수 있습니다.' WHERE content_id = '2922525';
UPDATE places SET overview = '룰루레몬은 건강한 삶의 즐거움을 전파하는 글로벌 프리미엄 요가 및 기능성 스포츠 웨어 브랜드입니다. 독보적인 기술력의 원단과 세련된 디자인을 통해 운동할 때는 물론 일상에서도 최상의 편안함과 자신감을 선사합니다.' WHERE content_id = '2928162';
