UPDATE places SET overview = '발렌시아가는 파격적인 디자인과 구조적인 실루엣으로 패션계의 흐름을 주도하는 글로벌 하이엔드 럭셔리 브랜드입니다. 아방가르드한 감성과 스트릿 무드를 결합하여 전 세계 패셔니스타들의 열광적인 지지를 받고 있습니다.' WHERE content_id = '2916034';
