UPDATE places SET overview = '삼성온누리약국은 온누리 체인의 전문 상담 매뉴얼과 삼성의 신뢰감을 바탕으로 한 수준 높은 건강 서비스를 제공합니다. 정확한 조제 시스템과 맞춤형 영양 요법 제안을 통해 지역 사회의 든든한 건강 동반자 역할을 수행합니다.' WHERE content_id = '4026761';
