UPDATE places SET overview = 'Apple은 혁신적인 기술과 직관적인 디자인으로 전 세계의 디지털 문화를 선도하는 글로벌 IT 브랜드입니다. iPhone, Mac, iPad 등 모든 기기가 조화롭게 연결되는 독보적인 생태계를 통해 고객에게 경이로운 사용자 경험과 창의적인 일상을 선사합니다.' WHERE content_id = '2930410';
UPDATE places SET overview = '아티지(ARTAGE)는 현대적인 감각의 글로벌 남성 컨템포러리 브랜드들을 전문적으로 소개하는 셀렉트 숍입니다. 유행에 휩쓸리지 않는 아티스틱한 안목으로 큐레이션된 의류와 잡화를 통해 품격 있고 차별화된 남성 스타일을 제안합니다.' WHERE content_id = '2922988';
UPDATE places SET overview = '바투타라716은 미지의 섬을 탐험하듯 새로운 영감과 즐거움을 선사하는 라이프스타일 편집 브랜드입니다. 독창적인 감각으로 큐레이션된 전 세계의 패션 및 소품들을 통해 고객의 취향을 한 차원 높여주는 특별한 발견의 기쁨을 제공합니다.' WHERE content_id = '4026664';
