UPDATE places SET overview = 'H&M은 전 세계 패션 트렌드를 선도하는 글로벌 SPA 브랜드로, 패션과 품질을 가장 합리적인 가격에 제공합니다. 지속 가능한 패션을 위해 끊임없이 노력하며 전 연령층을 아우르는 다채로운 컬렉션을 선보입니다.' WHERE content_id = '2895304';
UPDATE places SET overview = 'IWC 샤프하우젠은 정교한 공학적 기술력과 시대를 앞서가는 혁신을 결합한 스위스 럭셔리 워치 브랜드입니다. ''파일럿 워치'', ''포르투기저'' 등 역사적인 컬렉션을 통해 전문성과 클래식한 미학이 조화를 이룬 타임피스를 전 세계에 선보입니다.' WHERE content_id = '2917193';
